"use client";

import { Dialog as DialogPrimitive } from "@base-ui/react/dialog";
import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { XIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import type { _BaseDivProps, PropsWithStylex } from "@/utils/stylex.utils";
import { Button } from "../Button/button";
import { ScrollArea } from "../ScrollArea/scroll-area";
import { dialogStyles } from "./dialog.styles";

type ClassNameProp<State> = string | ((state: State) => string | undefined);

function mergeClassName<State>(
	baseClassName: string,
	className?: ClassNameProp<State>,
) {
	const resolvedClassName =
		typeof className === "function" ? className({} as State) : className;
	return [baseClassName, resolvedClassName].filter(Boolean).join(" ");
}

const DialogCreateHandle: typeof DialogPrimitive.createHandle =
	DialogPrimitive.createHandle;

const Dialog: typeof DialogPrimitive.Root = DialogPrimitive.Root;

const DialogPortal: typeof DialogPrimitive.Portal = DialogPrimitive.Portal;

function DialogTrigger(
	props: DialogPrimitive.Trigger.Props,
): React.ReactElement {
	return <DialogPrimitive.Trigger data-slot="dialog-trigger" {...props} />;
}

export function DialogClose(
	props: DialogPrimitive.Close.Props,
): React.ReactElement {
	return <DialogPrimitive.Close data-slot="dialog-close" {...props} />;
}

export function DialogBackdrop(
	props: DialogPrimitive.Backdrop.Props,
): React.ReactElement {
	return (
		<DialogPrimitive.Backdrop
			{...stylex.props(dialogStyles.backdrop)}
			data-slot="dialog-backdrop"
			{...props}
		/>
	);
}
type DialogViewportProps = PropsWithStylex<DialogPrimitive.Viewport.Props>;
export function DialogViewport({
	style,
	...props
}: DialogViewportProps): React.ReactElement {
	return (
		<DialogPrimitive.Viewport
			{...stylex.props(dialogStyles.viewport, style)}
			data-slot="dialog-viewport"
			{...props}
		/>
	);
}

export function DialogPopup({
	className,
	children,
	showCloseButton = true,
	bottomStickOnMobile = true,
	closeProps,
	portalProps,
	...props
}: DialogPrimitive.Popup.Props & {
	showCloseButton?: boolean;
	bottomStickOnMobile?: boolean;
	closeProps?: DialogPrimitive.Close.Props;
	portalProps?: DialogPrimitive.Portal.Props;
}): React.ReactElement {
	const popupProps = stylex.props(
		dialogStyles.popup,
		bottomStickOnMobile && dialogStyles.popupBottomStickOnMobile,
	);
	return (
		<DialogPortal {...portalProps}>
			<DialogBackdrop />
			<DialogViewport
				{...stylex.props(
					dialogStyles.viewportShell,
					bottomStickOnMobile && dialogStyles.viewportShellBottomStickOnMobile,
				)}
			>
				<DialogPrimitive.Popup
					className={mergeClassName(popupProps.className ?? "", className)}
					data-slot="dialog-popup"
					{...props}
				>
					{children}
					{showCloseButton && (
						<DialogPrimitive.Close
							aria-label="Close"
							className={stylex.props(dialogStyles.closeButton).className}
							render={<Button size="small" variant="ghost" />}
							{...closeProps}
						>
							<XIcon />
						</DialogPrimitive.Close>
					)}
				</DialogPrimitive.Popup>
			</DialogViewport>
		</DialogPortal>
	);
}

type HeaderProps = useRender.ComponentProps<"div">;

export function DialogHeader({
	className,
	render,
	...props
}: HeaderProps): React.ReactElement {
	const headerProps = stylex.props(dialogStyles.header);
	return useRender({
		defaultTagName: "div",
		props: mergeProps<"div">(
			{
				...headerProps,
				className: mergeClassName(headerProps.className ?? "", className),
				"data-slot": "dialog-header",
			} as never,
			props,
		),
		render,
	});
}

type FooterProps = _BaseDivProps & {
	variant?: "default" | "bare";
};

export function DialogFooter({
	style,
	variant = "default",
	render,
	...props
}: FooterProps): React.ReactElement {
	const footerProps = stylex.props(
		dialogStyles.footer,
		variant === "default" && dialogStyles.footerDefault,
		variant === "bare" && dialogStyles.footerBare,
		style,
	);
	return useRender({
		defaultTagName: "div",
		props: mergeProps<"div">(
			{
				...footerProps,
				"data-slot": "dialog-footer",
			} as never,
			props,
		),
		render,
	});
}

export function DialogTitle(
	props: DialogPrimitive.Title.Props,
): React.ReactElement {
	return (
		<DialogPrimitive.Title
			{...stylex.props(dialogStyles.title)}
			data-slot="dialog-title"
			{...props}
		/>
	);
}

export function DialogDescription(
	props: DialogPrimitive.Description.Props,
): React.ReactElement {
	return (
		<DialogPrimitive.Description
			{...stylex.props(dialogStyles.description)}
			data-slot="dialog-description"
			{...props}
		/>
	);
}

function DialogPanel({
	className,
	scrollFade = true,
	render,
	...props
}: useRender.ComponentProps<"div"> & {
	scrollFade?: boolean;
}): React.ReactElement {
	const panelProps = stylex.props(
		dialogStyles.panel,
		scrollFade && dialogStyles.panelScrollFade,
	);
	return (
		<ScrollArea scrollFade={scrollFade}>
			{useRender({
				defaultTagName: "div",
				props: mergeProps<"div">(
					{
						...panelProps,
						className: mergeClassName(panelProps.className ?? "", className),
						"data-slot": "dialog-panel",
					} as never,
					props,
				),
				render,
			})}
		</ScrollArea>
	);
}

export type { DialogViewportProps };

export {
	Dialog,
	DialogBackdrop as DialogOverlay,
	DialogCreateHandle,
	DialogPanel,
	DialogPopup as DialogContent,
	DialogPortal,
	DialogPrimitive,
	DialogTrigger,
};

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { borderRadius, borderWidth, spacing } from "@/lib/theme/tokens.stylex";

export const dialogStyles = stylex.create({
	backdrop: {
		position: "fixed",
		inset: 0,
		zIndex: 50,
		backgroundColor: "rgba(0, 0, 0, 0.32)",
		backdropFilter: "blur(4px)",
		transitionProperty: "opacity, transform",
		transitionDuration: "200ms",
	},
	viewport: {
		position: "fixed",
		inset: 0,
		zIndex: 50,
		display: "grid",
		gridTemplateRows: "1fr auto 3fr",
		justifyItems: "center",
		padding: spacing.medium,
		boxSizing: "border-box",
	},
	viewportShell: {
		":is([data-slot='dialog-viewport'])": {
			display: "grid",
		},
	},
	viewportShellBottomStickOnMobile: {},
	popup: {
		position: "relative",
		gridRowStart: 2,
		display: "flex",
		flexDirection: "column",
		width: "100%",
		minWidth: 0,
		maxWidth: "32rem",
		maxHeight: "100%",
		minHeight: 0,
		transformOrigin: "center",
		borderWidth: borderWidth.thin,
		borderStyle: "solid",
		borderColor: theme.border,
		borderRadius: borderRadius.xlarge,
		backgroundColor: theme.surface,
		color: theme.contentPrimary,
		boxSizing: "border-box",
		opacity: "calc(1 - var(--nested-dialogs))",
		outline: "none",
		transitionProperty: "transform, opacity",
		transitionDuration: "200ms",
		transitionTimingFunction: "ease-in-out",
		willChange: "transform",
		"::before": {
			content: '""',
			pointerEvents: "none",
			position: "absolute",
			inset: 0,
			borderRadius: "calc(16px - 1px)",
			boxShadow:
				"0 1px 0 rgba(0, 0, 0, 0.04), inset 0 0 0 1px rgba(255, 255, 255, 0.02)",
		},
	},
	popupBottomStickOnMobile: {},
	closeButton: {
		position: "absolute",
		top: spacing.small,
		insetInlineEnd: spacing.small,
	},
	header: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.small,
		padding: spacing.large,
		boxSizing: "border-box",
		"[data-has-panel]": {
			paddingBottom: spacing.small,
		},
	},
	footer: {
		display: "flex",
		flexDirection: "column-reverse",
		gap: spacing.small,
		paddingLeft: spacing.large,
		paddingRight: spacing.large,
		boxSizing: "border-box",
	},
	footerDefault: {
		borderTopWidth: borderWidth.thin,
		borderTopStyle: "solid",
		borderTopColor: theme.borderSubtle,
		backgroundColor: theme.backgroundSubtle,
		paddingTop: spacing.medium,
		paddingBottom: spacing.medium,
	},
	footerBare: {
		paddingTop: spacing.medium,
		paddingBottom: spacing.large,
		":has([data-slot='dialog-popup']:has([data-slot='dialog-panel']))": {
			paddingTop: spacing.small,
		},
	},
	title: {
		fontSize: "20px",
		lineHeight: 1,
		fontWeight: 600,
		color: theme.contentPrimary,
	},
	description: {
		fontSize: "14px",
		lineHeight: 1.4,
		color: theme.contentSecondary,
	},
	panelScrollFade: { opacity: 1 },
	panel: {
		boxSizing: "border-box",
		padding: spacing.large,
		":has([data-slot='dialog-popup']:has([data-slot='dialog-header']))": {
			paddingTop: spacing.xsmall,
		},
		// ":has([data-slot='dialog-popup']:has([data-slot='dialog-footer']:not(.border-t))":
		// 	{
		// 		paddingBottom: spacing.xsmall,
		// 	},
	},
});
